import React, { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { useAuth, API } from '../App';
export default function Register() {
  const [form, setForm] = useState({ name: '', email: '', password: '' });
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const { login } = useAuth();
  const navigate = useNavigate();
  const handleSubmit = async (e) => {
    e.preventDefault(); setLoading(true); setError('');
    try {
      const res = await fetch(`${API}/api/auth/register`, { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(form) });
      const data = await res.json();
      if (!res.ok) throw new Error(data.detail || 'Registration failed');
      login(data.user, data.token); navigate('/dashboard');
    } catch (err) { setError(err.message); } finally { setLoading(false); }
  };
  const inp = { width: '100%', padding: '12px', marginBottom: '12px', borderRadius: '8px', border: '1px solid #333', background: '#111', color: '#fff', fontSize: '16px', boxSizing: 'border-box' };
  return (
    <div style={{ minHeight: '100vh', display: 'flex', alignItems: 'center', justifyContent: 'center', background: '#0f0f0f' }}>
      <div style={{ background: '#1a1a1a', padding: '40px', borderRadius: '12px', width: '100%', maxWidth: '400px' }}>
        <h1 style={{ color: '#fff', marginBottom: '8px' }}>🏋️ GymVision AI</h1>
        <p style={{ color: '#888', marginBottom: '24px' }}>Create your account</p>
        {error && <div style={{ background: '#ff444420', color: '#ff4444', padding: '10px', borderRadius: '8px', marginBottom: '16px' }}>{error}</div>}
        <form onSubmit={handleSubmit}>
          <input style={inp} placeholder="Full Name" value={form.name} onChange={e => setForm({...form, name: e.target.value})} required />
          <input style={inp} type="email" placeholder="Email" value={form.email} onChange={e => setForm({...form, email: e.target.value})} required />
          <input style={{...inp, marginBottom: '20px'}} type="password" placeholder="Password" value={form.password} onChange={e => setForm({...form, password: e.target.value})} required />
          <button type="submit" disabled={loading} style={{ width: '100%', padding: '12px', borderRadius: '8px', border: 'none', background: '#6c63ff', color: '#fff', fontSize: '16px', fontWeight: 'bold', cursor: 'pointer' }}>
            {loading ? 'Creating account...' : 'Create Account'}
          </button>
        </form>
        <p style={{ color: '#888', textAlign: 'center', marginTop: '16px' }}>Already have an account? <Link to="/login" style={{ color: '#6c63ff' }}>Sign in</Link></p>
      </div>
    </div>
  );
}
